    public Document loadConfig(String configPath) throws Exception {
        // 1. Input Validation
        if (configPath == null || configPath.trim().isEmpty()) {
            throw new IllegalArgumentException("Configuration path cannot be null or empty.");
        }

        File xmlFile = new File(configPath);
        if (!xmlFile.exists() || !xmlFile.isFile()) {
            throw new IOException("File not found or is not a file: " + configPath);
        }

        try {
            // 2. Initialize Factory
            DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();

            // 3. SECURITY: Prevent XXE (XML External Entity) Injection
            // This is critical when processing user-uploaded XML files.

            // Disallow DOCTYPE declarations entirely (safest for config files)
            dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

            // Disable external entities
            dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
            dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);

            // Disable external DTDs
            dbf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

            // Disable XInclude
            dbf.setXIncludeAware(false);

            // Disable entity reference expansion
            dbf.setExpandEntityReferences(false);

            // 4. Create Builder and Parse
            DocumentBuilder db = dbf.newDocumentBuilder();
            Document doc = db.parse(xmlFile);

            // 5. Normalize the document (good practice for DOM manipulation)
            doc.getDocumentElement().normalize();

            return doc;

        } catch (ParserConfigurationException | SAXException | IOException e) {
            // Log the exception here if a logger is available
            throw e;
        } catch (Exception e) {
            throw new Exception("An unexpected error occurred while parsing the XML configuration.", e);
        }
    }
}
